     1→import { createServer } from 'node:http';
     2→import { resolve, isAbsolute } from 'node:path';
     3→import { watch } from 'node:fs';
     4→import { pruneWorktrees, findGitRepo } from './git/worktree.js';
     5→import { loadConfig } from './config/loader.js';
     6→import { configExists, runSetup } from './config/setup.js';
     7→import { StateStore } from './state/store.js';
     8→import { PipelineManager } from './pipeline/manager.js';
     9→import { createApp } from './web/server.js';
    10→import { attachWebSocket } from './web/ws-handler.js';
    11→
    12→const DEV_MODE = process.env.JIRANIMO_MODE === 'development';
    13→const SELF_MODE = DEV_MODE && process.env.JIRANIMO_SELF === '1';
    14→
    15→async function main() {
    16→  if (DEV_MODE) {
    17→    console.log(`\n[DEV] Running in development mode${SELF_MODE ? ' (self)' : ''}\n`);
    18→  }
    19→
    20→  // Load config — dev uses local file, prod uses global
    21→  let config;
    22→  if (DEV_MODE) {
    23→    const devConfigPath = resolve(process.cwd(), 'jiranimo.dev.config.json');
    24→    config = loadConfig({ configPath: devConfigPath });
    25→    // Self mode: operate on the Jiranimo repo itself instead of gitPlaygrounds
    26→    if (SELF_MODE) {
    27→      config = { ...config, repoPath: resolve(process.cwd(), '..') };
    28→    } else if (!isAbsolute(config.repoPath)) {
    29→      // Resolve relative repoPath against cwd
    30→      config = { ...config, repoPath: resolve(process.cwd(), config.repoPath) };
    31→    }
    32→    // Set dev-local paths (self mode gets its own state to avoid conflicts)
    33→    const statePrefix = SELF_MODE ? '.dev-self' : '.dev';
    34→    config.statePath = config.statePath ?? resolve(process.cwd(), `${statePrefix}-state.json`);
    35→    config.logsDir = config.logsDir ?? resolve(process.cwd(), `${statePrefix}-logs`);
    36→  } else {
    37→    if (!configExists()) {
    38→      await runSetup();
    39→    }
    40→    config = loadConfig();
    41→  }
    42→
    43→  // Prune stale worktrees from previous crashes
    44→  const gitRepo = await findGitRepo(config.repoPath);
    45→  if (gitRepo) {
    46→    await pruneWorktrees(gitRepo);
    47→    console.log(`Pruned stale worktrees in ${gitRepo}`);
    48→  }
    49→
    50→  // State — dev uses local file, prod uses global default
    51→  const store = new StateStore(config.statePath ? { filePath: config.statePath } : undefined);
    52→  const pipeline = new PipelineManager(store, config);
    53→
    54→  const app = createApp(store, pipeline);
    55→  const server = createServer(app);
    56→  const wsHandler = attachWebSocket(server, pipeline);
    57→
    58→  // In dev mode, watch extension files and broadcast reload signal
    59→  if (DEV_MODE) {
    60→    startExtensionWatcher(wsHandler);
    61→  }
    62→
    63→  server.listen(config.web.port, config.web.host, () => {
    64→    console.log(`Jiranimo server running on http://${config.web.host}:${config.web.port}`);
    65→    console.log(`Dashboard: http://${config.web.host}:${config.web.port}`);
    66→    console.log(`Repo path: ${config.repoPath}`);
    67→
    68→    if (DEV_MODE) {
    69→      console.log(`\n[DEV] Config: ${resolve(process.cwd(), 'jiranimo.dev.config.json')}`);
    70→      console.log(`[DEV] State: ${config.statePath}`);
    71→      console.log(`[DEV] Logs: ${config.logsDir}`);
    72→      console.log(`[DEV] Extension auto-reload: enabled`);
    73→    } else {
    74→      const extensionPath = resolve(process.cwd(), '..', 'extension');
    75→      console.log(`\nTo install the Chrome extension:`);
    76→      console.log(`  1. Open chrome://extensions`);
    77→      console.log(`  2. Enable "Developer mode" (top right)`);
    78→      console.log(`  3. Click "Load unpacked"`);
    79→      console.log(`  4. Select: ${extensionPath}`);
    80→    }
    81→    console.log('');
    82→  });
    83→
    84→  let shuttingDown = false;
    85→  function shutdown() {
    86→    if (shuttingDown) return;
    87→    shuttingDown = true;
    88→    console.log('\nShutting down...');
    89→    store.flushSync();
    90→    store.destroy();
    91→    server.close(() => process.exit(0));
    92→    setTimeout(() => process.exit(0), 2000).unref();
    93→  }
    94→
    95→  process.on('SIGINT', shutdown);
    96→  process.on('SIGTERM', shutdown);
    97→}
    98→
    99→function startExtensionWatcher(wsHandler: ReturnType<typeof attachWebSocket>) {
   100→  const extensionDir = resolve(process.cwd(), '..', 'extension');
   101→  let debounceTimer: ReturnType<typeof setTimeout> | null = null;
   102→
   103→  try {
   104→    watch(extensionDir, { recursive: true }, (_event, filename) => {
   105→      if (!filename || filename.includes('node_modules')) return;
   106→      // Debounce — wait 500ms for batch changes
   107→      if (debounceTimer) clearTimeout(debounceTimer);
   108→      debounceTimer = setTimeout(() => {
   109→        console.log(`[DEV] Extension file changed: ${filename}`);
   110→        wsHandler.send({ type: 'extension-reload' });
   111→      }, 500);
   112→    });
   113→    console.log(`[DEV] Watching extension/ for changes`);
   114→  } catch (err) {
   115→    console.warn(`[DEV] Could not watch extension directory:`, err);
   116→  }
   117→}
   118→
   119→main();
