     4→import { homedir } from 'node:os';
     5→import { writeFileSync } from 'node:fs';
     6→import type { ServerConfig } from '../config/types.js';
     7→import type { TaskRecord, TaskStatus } from '../state/types.js';
     8→import type { ClaudeEvent, ExecutionResult, TaskInput } from '../claude/types.js';
     9→import { StateStore } from '../state/store.js';
    10→import { transition } from './state-machine.js';
    11→import { buildPrompt } from '../claude/prompt-builder.js';
    12→import { executeClaudeCode } from '../claude/executor.js';
    13→import { commitAndPush } from '../git/branch.js';
    14→import { createWorktree, removeWorktree, findGitRepo, detectDefaultBranch } from '../git/worktree.js';
    15→import { branchName } from '../git/branch.js';
    16→import { createDraftPr, buildPrTitle, buildPrBody } from '../git/pr.js';
    17→
    18→export class PipelineManager extends EventEmitter {
    19→  private store: StateStore;
    20→  private config: ServerConfig;
    21→  private activeCount = 0;
    22→  private queue: string[] = [];
    23→  private processing = false;
    24→
    25→  constructor(store: StateStore, config: ServerConfig) {
    26→    super();
    27→    this.store = store;
    28→    this.config = config;
    29→  }
    30→
    31→  submitTask(input: TaskInput): TaskRecord {
    32→    const existing = this.store.getTask(input.key);
    33→    if (existing && (existing.status === 'queued' || existing.status === 'in-progress')) {
    34→      throw new Error(`Task ${input.key} is already ${existing.status}`);
    35→    }
    36→
    37→    const task: TaskRecord = {
    38→      key: input.key,
    39→      summary: input.summary,
    40→      description: input.description,
    41→      acceptanceCriteria: input.acceptanceCriteria,
    42→      priority: input.priority,
    43→      issueType: input.issueType,
    44→      labels: input.labels,
    45→      comments: input.comments,
    46→      subtasks: input.subtasks,
    47→      linkedIssues: input.linkedIssues,
    48→      attachments: input.attachments,
    49→      assignee: input.assignee,
    50→      reporter: input.reporter,
    51→      components: input.components,
    52→      parentKey: input.parentKey,
    53→      jiraUrl: input.jiraUrl,
    54→      status: 'queued',
    55→      // Preserve branch name from previous attempt so we continue on the same branch
    56→      branchName: existing?.branchName,
    57→      createdAt: new Date().toISOString(),
    58→      updatedAt: new Date().toISOString(),
    59→    };
    60→
    61→    this.store.upsertTask(task);
    62→    this.store.flushSync();
    63→    this.queue.push(task.key);
    64→    this.emit('task-created', task);
    65→    setImmediate(() => this.processQueue());
    66→    return task;
    67→  }
    68→
    69→  retryTask(key: string): TaskRecord {
    70→    const task = this.store.getTask(key);
    71→    if (!task) throw new Error(`Task ${key} not found`);
    72→
    73→    const newStatus = transition(task.status, 'retry');
    74→    const oldStatus = task.status;
    75→    this.store.updateTaskStatus(key, newStatus, { errorMessage: undefined });
    76→    this.store.flushSync();
    77→    this.queue.push(key);
    78→    this.emit('task-status-changed', this.store.getTask(key)!, oldStatus);
    79→    setImmediate(() => this.processQueue());
    80→    return this.store.getTask(key)!;
    81→  }
    82→
    83→  private processQueue(): void {
    84→    if (this.processing) return;
    85→    this.processing = true;
    86→
    87→    try {
    88→      while (this.queue.length > 0 && this.activeCount < this.config.pipeline.concurrency) {
    89→        const key = this.queue.shift();
    90→        if (!key) break;
    91→        const task = this.store.getTask(key);
    92→        if (!task) continue;
    93→        this.runTask(key);
    94→      }
    95→    } finally {
    96→      this.processing = false;
    97→    }
    98→  }
    99→
   100→  private transitionTask(key: string, action: 'start' | 'complete' | 'fail', extra?: Partial<TaskRecord>): void {
   101→    const task = this.store.getTask(key);
   102→    if (!task) return;
   103→    const oldStatus = task.status;
   104→    const newStatus = transition(task.status, action);
   105→    this.store.updateTaskStatus(key, newStatus, extra);
   106→    this.store.flushSync();
   107→    const updated = this.store.getTask(key)!;
   108→    this.emit('task-status-changed', updated, oldStatus);
   109→    if (newStatus === 'completed' || newStatus === 'failed') {
   110→      this.emit('task-completed', updated);
   111→    }
   112→  }
   113→
   114→  private async runTask(key: string): Promise<void> {
   115→    const task = this.store.getTask(key)!;
   116→    const repoRoot = this.config.repoPath;
   117→
   118→    this.activeCount++;
   119→    console.log(`\n${'='.repeat(60)}`);
   120→    console.log(`[PIPELINE] Starting task: ${task.key} — ${task.summary} (${this.activeCount}/${this.config.pipeline.concurrency} active)`);
   121→    console.log(`[PIPELINE] Repo root: ${repoRoot}`);
   122→    console.log(`${'='.repeat(60)}`);
   123→    this.transitionTask(key, 'start', { startedAt: new Date().toISOString() });
   124→
   125→    const logsDir = this.config.logsDir ?? resolve(homedir(), '.jiranimo', 'logs');
   126→    mkdirSync(logsDir, { recursive: true });
   127→    const logPath = join(logsDir, `${key}-${Date.now()}.jsonl`);
   128→    const logLines: string[] = [];
   129→    let worktreePath: string | null = null;
   130→    let gitRepoPath: string | null = null;
   131→
   132→    try {
   133→      // 1. Find the git repo inside repoRoot
   134→      gitRepoPath = await findGitRepo(repoRoot);
   135→      if (!gitRepoPath) {
   136→        throw new Error(`No git repository found in ${repoRoot}`);
   137→      }
   138→      console.log(`[PIPELINE] Git repo: ${gitRepoPath}`);
   139→
   140→      // Detect the actual default branch (config may say 'main' but repo uses 'master')
   141→      const baseBranch = await detectDefaultBranch(gitRepoPath, this.config.git.pushRemote);
   142→      console.log(`[PIPELINE] Base branch: ${baseBranch}`);
   143→
   144→      // 2. Create a worktree for this task (isolated from user's working directory)
   145→      // Reuse existing branch name if this is a re-implementation, otherwise generate a new one
   146→      const branch = task.branchName ?? branchName(this.config.git.branchPrefix, task.key, task.summary);
   147→      worktreePath = await createWorktree(
   148→        gitRepoPath,
   149→        task.key,
   150→        branch,
   151→        baseBranch,
   152→        this.config.git.pushRemote,
   153→      );
   154→      console.log(`[PIPELINE] Worktree created: ${worktreePath}`);
   155→      console.log(`[PIPELINE] Branch: ${branch}`);
   156→      this.store.updateTaskStatus(key, 'in-progress', { branchName: branch });
   157→
   158→      // 3. Build prompt and run Claude in the worktree
   159→      const prompt = buildPrompt(task, this.config.claude.appendSystemPrompt);
   160→
   161→      console.log(`[PIPELINE] Prompt built (${prompt.length} chars)`);
   162→      console.log(`[PIPELINE] Spawning Claude Code in worktree...`);
   163→      console.log(`${'─'.repeat(60)}`);
   164→
   165→      let sessionLogged = false;
   166→      const result: ExecutionResult = await executeClaudeCode({
   167→        prompt,
   168→        cwd: worktreePath,
   169→        config: this.config.claude,
   170→        timeoutMs: 30 * 60 * 1000,
   171→        onEvent: (event: ClaudeEvent) => {
   172→          logLines.push(JSON.stringify(event.raw));
   173→          this.emit('task-output', key, JSON.stringify(event.raw));
   174→          if (event.text) {
   175→            console.log(`[CLAUDE] ${event.text}`);
   176→          } else if (event.type === 'init' && event.sessionId && !sessionLogged) {
   177→            sessionLogged = true;
   178→            console.log(`[CLAUDE] Session started: ${event.sessionId}`);
   179→          } else if (event.type === 'result') {
   180→            console.log(`[CLAUDE] Result: ${event.isError ? 'ERROR' : 'SUCCESS'} — ${event.text?.slice(0, 200) || ''}`);
   181→          }
   182→        },
   183→        onOutput: (raw: string) => {
   184→          for (const line of raw.split('\n')) {
   185→            const trimmed = line.trim();
   186→            if (trimmed && !trimmed.startsWith('{')) {
   187→              console.log(`[CLAUDE RAW] ${trimmed}`);
   188→            }
   189→          }
   190→        },
   191→      });
   192→
   193→      console.log(`${'─'.repeat(60)}`);
   194→      console.log(`[PIPELINE] Claude finished — success: ${result.success}, cost: $${result.costUsd ?? 0}, duration: ${result.durationMs}ms`);
   195→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   196→      console.log(`[PIPELINE] Logs saved to: ${logPath}`);
   197→
   198→      if (!result.success) {
   199→        throw new Error(result.resultText);
   200→      }
   201→
   202→      // 4. Commit and push from the worktree
   203→      await commitAndPush(
   204→        worktreePath,
   205→        branch,
   206→        task.key,
   207→        task.summary,
   208→        task.issueType,
   209→        task.jiraUrl,
   210→        this.config.git.pushRemote,
   211→      );
   212→      console.log(`[PIPELINE] Changes committed and pushed`);
   213→
   214→      // 5. Create a draft PR if configured
   215→      let prUrl: string | undefined;
   216→      let prNumber: number | undefined;
   217→      if (this.config.git.createDraftPr) {
   218→        try {
   219→          const pr = await createDraftPr({
   220→            cwd: worktreePath,
   221→            baseBranch,
   222→            headBranch: branch,
   223→            title: buildPrTitle(task.key, task.summary),
   224→            body: buildPrBody({
   225→              issueKey: task.key,
   226→              summary: task.summary,
   227→              description: task.description,
   228→              jiraUrl: task.jiraUrl,
   229→              resultText: result.resultText,
   230→              costUsd: result.costUsd,
   231→              durationMs: result.durationMs,
   232→            }),
   233→          });
   234→          prUrl = pr.url;
   235→          prNumber = pr.number;
   236→          console.log(`[PIPELINE] Draft PR created: ${prUrl}`);
   237→        } catch (err) {
   238→          console.warn(`[PIPELINE] PR creation failed (non-fatal): ${(err as Error).message}`);
   239→        }
   240→      }
   241→
   242→      this.transitionTask(key, 'complete', {
   243→        claudeSessionId: result.sessionId,
   244→        claudeCostUsd: result.costUsd,
   245→        claudeResultText: result.resultText,
   246→        prUrl,
   247→        prNumber,
   248→        logPath,
   249→        completedAt: new Date().toISOString(),
   250→      });
   251→      console.log(`[PIPELINE] ✓ Task ${key} completed successfully`);
   252→      console.log(`${'='.repeat(60)}\n`);
   253→    } catch (err) {
   254→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   255→      console.error(`[PIPELINE] ✗ Task ${key} failed: ${(err as Error).message}`);
   256→      console.log(`[PIPELINE] Logs: ${logPath}`);
   257→      console.log(`${'='.repeat(60)}\n`);
   258→      this.transitionTask(key, 'fail', {
   259→        errorMessage: (err as Error).message,
   260→        logPath,
   261→      });
   262→    } finally {
   263→      // 5. Clean up worktree
   264→      if (worktreePath && gitRepoPath) {
   265→        try {
   266→          await removeWorktree(gitRepoPath, worktreePath);
   267→          console.log(`[PIPELINE] Worktree removed: ${worktreePath}`);
   268→        } catch (err) {
   269→          console.warn(`[PIPELINE] Failed to remove worktree: ${(err as Error).message}`);
   270→        }
   271→      }
   272→      this.activeCount--;
   273→      this.processQueue();
   274→    }
   275→  }
   276→}
