     7→export function slugify(text: string, maxLength = 40): string {
     8→  return text
     9→    .toLowerCase()
    10→    .replace(/[^a-z0-9]+/g, '-')
    11→    .replace(/^-|-$/g, '')
    12→    .substring(0, maxLength)
    13→    .replace(/-$/, '');
    14→}
    15→
    16→export function branchName(prefix: string, issueKey: string, summary: string): string {
    17→  const slug = slugify(summary);
    18→  const rid = Math.random().toString(36).substring(2, 5);
    19→  return `${prefix}${issueKey}-${slug}-${rid}`;
    20→}
    21→
    22→export function commitType(issueType: string): string {
    23→  const lower = issueType.toLowerCase();
    24→  if (lower === 'bug') return 'fix';
    25→  if (lower === 'story' || lower === 'feature') return 'feat';
    26→  return 'chore';
    27→}
    28→
    29→export function commitMessage(issueKey: string, summary: string, issueType: string): string {
    30→  return `${commitType(issueType)}(${issueKey}): ${summary}`;
    31→}
    32→
    33→async function git(args: string[], cwd: string): Promise<string> {
    34→  try {
    35→    const { stdout } = await exec('git', args, { cwd });
    36→    return stdout.trim();
    37→  } catch (err: unknown) {
    38→    const e = err as { stderr?: string; message: string };
    39→    const stderr = e.stderr?.trim();
    40→    throw new Error(stderr || e.message);
    41→  }
    42→}
    43→
    44→export async function setupBranch(
    45→  cwd: string,
    46→  issueKey: string,
    47→  summary: string,
    48→  config: GitConfig,
    49→  baseBranchOverride?: string,
    50→): Promise<string> {
    51→  const base = baseBranchOverride ?? config.defaultBaseBranch;
    52→  const branch = branchName(config.branchPrefix, issueKey, summary);
    53→
    54→  // Try to fetch from remote — skip gracefully if no remote exists
    55→  const hasRemote = await git(['remote'], cwd).then(r => r.length > 0).catch(() => false);
    56→  if (hasRemote) {
    57→    await git(['fetch', config.pushRemote], cwd);
    58→  }
    59→
    60→  await git(['checkout', base], cwd);
    61→
    62→  if (hasRemote) {
    63→    await git(['pull', config.pushRemote, base], cwd).catch(() => {
    64→      // Pull may fail if remote branch doesn't exist yet — that's ok
    65→    });
    66→  }
    67→
    68→  await git(['checkout', '-b', branch], cwd);
    69→
    70→  return branch;
    71→}
    72→
    73→
    74→export async function commitAndPush(
    75→  cwd: string,
    76→  branch: string,
    77→  issueKey: string,
    78→  summary: string,
    79→  issueType: string,
    80→  jiraUrl: string,
    81→  remote: string,
    82→): Promise<void> {
    83→  await git(['add', '-A'], cwd);
    84→
    85→  const msg = `${commitMessage(issueKey, summary, issueType)}\n\nImplemented by Jiranimo + Claude Code\nJira: ${jiraUrl}`;
    86→  await git(['commit', '-m', msg], cwd);
    87→
    88→  // Push only if remote exists
    89→  const hasRemote = await git(['remote'], cwd).then(r => r.length > 0).catch(() => false);
    90→  if (hasRemote) {
    91→    await git(['push', '-u', remote, branch], cwd);
    92→  }
    93→}
